#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id directly
        stream << packet_id;

        // Write username with length prefix
        stream << hexi::prefixed(username);

        // Write scores count first, then the vector elements
        stream << static_cast<uint32_t>(scores.size()) << scores;

        // Write metadata as null-terminated string
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream
    hexi::binary_stream stream(adaptor);

    // Serialize the packet
    packet.serialise(stream);

    // Return the buffer containing serialized data
    return buffer;
}
```

