// Include the implementation
#include "implementation.hpp"

TEST(DynamicBuffer, PeekData) {
    hexi::dynamic_buffer<1024> buffer;
    std::vector<uint8_t> data = {1, 2, 3, 4, 5, 6, 7, 8};
    buffer.write(data.data(), data.size());

    auto peeked = peek_data_from_buffer(buffer, 3);

    EXPECT_EQ(3, peeked.size());
    EXPECT_EQ(1, peeked[0]);
    EXPECT_EQ(2, peeked[1]);
    EXPECT_EQ(3, peeked[2]);

    // Verify buffer size hasn't changed (peek doesn't consume)
    EXPECT_EQ(data.size(), buffer.size());
}

TEST(DynamicBuffer, PeekDoesNotConsume) {
    hexi::dynamic_buffer<1024> buffer;
    std::vector<uint8_t> data = {10, 20, 30, 40};
    buffer.write(data.data(), data.size());

    auto first_peek = peek_data_from_buffer(buffer, 2);
    auto second_peek = peek_data_from_buffer(buffer, 2);

    EXPECT_EQ(first_peek, second_peek);
    EXPECT_EQ(10, first_peek[0]);
    EXPECT_EQ(20, first_peek[1]);
}

TEST(DynamicBuffer, PeekAllData) {
    hexi::dynamic_buffer<1024> buffer;
    std::vector<uint8_t> data = {100, 200, 150};
    buffer.write(data.data(), data.size());

    auto peeked = peek_data_from_buffer(buffer, data.size());

    EXPECT_EQ(data, peeked);
}

