#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator with element_count pre-allocated blocks
    // Initially, all blocks are in the free list
    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===" << std::endl;
    std::cout << "Initial state - Free list contains " << element_count << " blocks" << std::endl;
    std::cout << "Storage active count: " << allocator.storage_active_count << std::endl;

    // Store allocated pointers
    std::vector<std::uint64_t*> allocated_blocks;

    // Demonstrate pop() behavior through allocate()
    // Each allocate() internally calls pop() to remove a block from free list head
    std::cout << "\n--- Phase 1: Allocating blocks (internally uses pop()) ---" << std::endl;
    for (size_t i = 0; i < element_count / 2; ++i) {
        std::uint64_t* block = allocator.allocate();
        allocated_blocks.push_back(block);
        *block = i * 100; // Write some data
        std::cout << "Allocated block " << i << " at " << block 
                  << " | Active: " << allocator.storage_active_count << std::endl;
    }

    std::cout << "\nTotal allocations so far: " << allocator.total_allocs << std::endl;
    std::cout << "Remaining free blocks: " << (element_count - allocator.storage_active_count) << std::endl;

    // Demonstrate push() behavior through deallocate()
    // Each deallocate() internally calls push() to add block back to free list head
    std::cout << "\n--- Phase 2: Deallocating blocks (internally uses push()) ---" << std::endl;
    std::vector<std::uint64_t*> deallocated_addrs;
    for (size_t i = 0; i < 3 && !allocated_blocks.empty(); ++i) {
        std::uint64_t* block = allocated_blocks.back();
        deallocated_addrs.push_back(block);
        std::cout << "Deallocating block at " << block << std::endl;
        allocator.deallocate(block);
        allocated_blocks.pop_back();
    }

    std::cout << "\nActive blocks after deallocation: " << allocator.storage_active_count << std::endl;
    std::cout << "Total deallocations: " << allocator.total_deallocs << std::endl;

    // Allocate again to demonstrate LIFO behavior of free list
    // The free list is a stack (push/pop), so we get blocks in reverse order
    std::cout << "\n--- Phase 3: Re-allocating (demonstrates LIFO free list) ---" << std::endl;
    std::cout << "Recently deallocated addresses (in order): ";
    for (auto* addr : deallocated_addrs) {
        std::cout << addr << " ";
    }
    std::cout << std::endl;

    std::cout << "\nAllocating 3 new blocks (should get deallocated ones in reverse):" << std::endl;
    for (size_t i = 0; i < 3; ++i) {
        std::uint64_t* reused_block = allocator.allocate();
        std::cout << "Re-allocated block at " << reused_block << std::endl;
        allocated_blocks.push_back(reused_block);
    }

    // Clean up remaining allocations
    std::cout << "\n--- Phase 4: Cleanup (push all blocks back) ---" << std::endl;
    for (auto* block : allocated_blocks) {
        allocator.deallocate(block);
    }

    std::cout << "\nFinal state:" << std::endl;
    std::cout << "Active blocks: " << allocator.storage_active_count << std::endl;
    std::cout << "Total allocations: " << allocator.total_allocs << std::endl;
    std::cout << "Total deallocations: " << allocator.total_deallocs << std::endl;
    std::cout << "\nAll blocks returned to free list!" << std::endl;
}
