#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Check if the buffer supports write seeking
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    // Seek the write position using the provided direction and offset
    // direction can be: begin (absolute), current (relative forward/backward), or end
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current write position (where the header will be written)
    std::size_t header_position = buffer.write_ptr();

    // Write header placeholder (4 bytes for uint32_t, initially zeros)
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(uint32_t));

    // Write body content here (example: write some data)
    // In a real scenario, you would write actual body data
    // For demonstration, let's write a simple body
    std::byte body_data[] = {std::byte{0x01}, std::byte{0x02}, std::byte{0x03}, std::byte{0x04}};
    buffer.write(body_data, sizeof(body_data));

    // Save position after writing body
    std::size_t after_body_position = buffer.write_ptr();

    // Seek back to header position (absolute seek from beginning)
    buffer.write_seek(hexi::buffer_seek::begin, header_position);

    // Update header with actual value
    buffer.write(&header_value, sizeof(uint32_t));

    // Seek back to the end of the written data (restore position after body)
    buffer.write_seek(hexi::buffer_seek::begin, after_body_position);
}

