template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Make value unsigned for bitwise operations
    using unsigned_type = std::make_unsigned_t<T>;
    unsigned_type uvalue = static_cast<unsigned_type>(value);

    do {
        std::uint8_t byte = uvalue & 0x7F; // Get lower 7 bits
        uvalue >>= 7; // Shift right by 7 bits

        if (uvalue != 0) {
            byte |= 0x80; // Set MSB if more bytes to come
        }

        writer << byte; // Write the byte
        bytes_written++;
    } while (uvalue != 0);

    return bytes_written;
}
