struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    try {
        throw; // Rethrow current exception
    } catch (const hexi::buffer_underrun& e) {
        return {e.read_size, e.total_read, e.buff_size, true};
    } catch (...) {
        return {0, 0, 0, false};
    }
}

